package com.vidaysalud.veterinaria.veterinarioservicio.repository; import com.vidaysalud.veterinaria.veterinarioservicio.model.Veterinario; import org.springframework.data.jpa.repository.JpaRepository; import java.util.*; public interface VeterinarioRepository extends JpaRepository<Veterinario,Integer>{Optional<Veterinario> findByEmail(String email);List<Veterinario> findByEspecialidadIgnoreCase(String especialidad);}